import{_ as t,a as i,o as a,aC as s}from"./chunks/framework.BX_mSSZJ.js";const g=JSON.parse('{"title":"About the Dashboard","description":"Aggregating the research and outputs of the ESA Earth System Science Hub within EarthCODE.","frontmatter":{"title":"About the Dashboard","description":"Aggregating the research and outputs of the ESA Earth System Science Hub within EarthCODE."},"headers":[],"relativePath":"about.md","filePath":"about.md"}'),r={name:"about.md"};function n(o,e,c,l,h,d){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="about-the-science-hub-dashboard-🌍" tabindex="-1">About the Science Hub Dashboard 🌍 <a class="header-anchor" href="#about-the-science-hub-dashboard-🌍" aria-label="Permalink to &quot;About the Science Hub Dashboard 🌍&quot;">​</a></h1><p>Welcome to the centralised knowledge and results dashboard for the <strong>ESA Earth System Science Hub</strong>, seamlessly integrated within the <strong>EarthCODE</strong> environment.</p><div class="tip custom-block"><p class="custom-block-title">Our Mission</p><p>To synthesise, visualise, and track the diverse research findings, algorithms, and collaborative scientific outputs emerging from the ESA Science Hub community into a single, interactive platform.</p></div><h2 id="what-is-the-esa-science-hub" tabindex="-1">What is the ESA Science Hub? <a class="header-anchor" href="#what-is-the-esa-science-hub" aria-label="Permalink to &quot;What is the ESA Science Hub?&quot;">​</a></h2><p>The <strong>Earth System Science Hub</strong> is the European Space Agency&#39;s premier facility for advanced Earth system and climate science studies. Located at ESA ESRIN in Frascati, Italy, it serves as a dynamic centre of excellence designed for:</p><ul><li><strong>Scientific Collaboration:</strong> Fostering a community response to the major environmental and climate science challenges of this decade.</li><li><strong>Networking &amp; Exchange:</strong> Welcoming scientists from all domains of Earth Observation (EO) and Earth system science to share ideas and methodologies.</li><li><strong>Boosting Output:</strong> Enhancing the scientific capabilities of ESA and its Member States by providing direct access to ESA&#39;s world-class expertise and infrastructure.</li></ul><h2 id="bringing-results-together" tabindex="-1">Bringing Results Together <a class="header-anchor" href="#bringing-results-together" aria-label="Permalink to &quot;Bringing Results Together&quot;">​</a></h2><p>This dashboard acts as the digital bridge between the physical and collaborative research conducted at the Science Hub and the open-science architecture of EarthCODE. Here, we bring together the Hub&#39;s distinct outputs:</p><div class="grid-container"><div class="grid-item"><h3>📊 Scientific Publications</h3><p>Direct access to the latest research papers, studies, and breakthroughs published by Science Hub researchers, fellows, and visiting scientists.</p></div><div class="grid-item"><h3>💻 Code &amp; Algorithms</h3><p>Open-source tools, Jupyter Notebooks, and processing algorithms developed during Science Hub projects, ready to be deployed directly within EarthCODE.</p></div><div class="grid-item"><h3>🌍 Project Insights</h3><p>Interactive summaries and data visualisations from ongoing Earth system science initiatives and University Challenges.</p></div></div><h2 id="highlighted-research-areas" tabindex="-1">Highlighted Research Areas <a class="header-anchor" href="#highlighted-research-areas" aria-label="Permalink to &quot;Highlighted Research Areas&quot;">​</a></h2><p>The Science Hub continually generates cutting-edge insights. By exploring this dashboard, you can track the results of major community projects, such as:</p><div class="info custom-block"><p class="custom-block-title">🌾 AI for Near Real-Time Crop Monitoring</p><p>Developing new transformer-based methods to enhance Green Area Index (GAI) retrieval using <strong>Sentinel-1</strong> and <strong>Sentinel-2</strong> data. This research delivers reliable, all-weather crop monitoring in near real-time.</p></div><div class="info custom-block"><p class="custom-block-title">🌲 European Forest Resilience</p><p>Studies led by ESRIN Internal Research Fellows that explore the relationship between forest structural diversity (FSD) and canopy structural complexity to better understand ecosystem resilience.</p></div><div class="info custom-block"><p class="custom-block-title">🏙️ Atmospheric &amp; Climate Probing</p><p>Tracking outcomes from key initiatives like the <strong>BAQUNIN project</strong> (probing the urban atmosphere from the ground) and advancements in spaceborne Doppler velocity measurements.</p></div><h2 id="get-involved" tabindex="-1">Get Involved <a class="header-anchor" href="#get-involved" aria-label="Permalink to &quot;Get Involved&quot;">​</a></h2><p>The Hub thrives on community engagement. Whether you are participating in the <strong>ESA Science Hub Challenges for Universities</strong>, attending our weekly <em>Hub Talks</em>, or joining as a visiting researcher, there are countless ways to contribute.</p><ul><li><strong>📍 Location:</strong> ESA ESRIN, via Galileo Galilei 1, Frascati (Rome), Italy</li><li><strong>✉️ Contact:</strong> <a href="mailto:sciencehub@esa.int" target="_blank" rel="noreferrer">sciencehub@esa.int</a></li><li><strong>🌐 Hub Website:</strong> <a href="https://sciencehub.esa.int/" target="_blank" rel="noreferrer">sciencehub.esa.int</a></li><li><strong>🚀 EO Science for Society:</strong> <a href="https://eo4society.esa.int/" target="_blank" rel="noreferrer">eo4society.esa.int</a></li></ul><blockquote><p><em>&quot;Join us in the exploration of our planet by becoming part of the vibrant scientific community at the Science Hub.&quot;</em></p></blockquote>',18)])])}const b=t(r,[["render",n]]);export{g as __pageData,b as default};
